import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Loans = ({ token }) => {
  const [loans, setLoans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [updating, setUpdating] = useState(false);

  const fetchLoans = async () => {
    try {
      const res = await axios.get('/api/admin/loans', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setLoans(res.data);
      setLoading(false);
    } catch (err) {
      setError('Failed to load loans');
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLoans();
  }, [token]);

  const updateLoanStatus = async (loanId, status) => {
    setUpdating(true);
    try {
      await axios.put(`/api/admin/loans/${loanId}`, { status }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // Refresh the list after update
      fetchLoans();
    } catch (err) {
      console.error('Update failed', err);
      alert('Failed to update loan status');
    } finally {
      setUpdating(false);
    }
  };

  if (loading) return <div>Loading loans...</div>;
  if (error) return <div style={{ color: 'red' }}>{error}</div>;

  return (
    <div>
      <h3>Loans</h3>
      {updating && <div>Updating loan...</div>}
      <table border="1" cellPadding="5" style={{ borderCollapse: 'collapse', width: '100%' }}>
        <thead>
          <tr>
            <th>ID</th>
            <th>User ID</th>
            <th>Amount</th>
            <th>Status</th>
            <th>Fee Paid</th>
            <th>Created</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {loans.map(loan => (
            <tr key={loan.id}>
              <td>{loan.id}</td>
              <td>{loan.user_id}</td>
              <td>{loan.amount}</td>
              <td>{loan.status}</td>
              <td>{loan.fee_paid ? 'Yes' : 'No'}</td>
              <td>{new Date(loan.created_at).toLocaleString()}</td>
              <td>
                {loan.status === 'pending' && (
                  <>
                    <button
                      onClick={() => updateLoanStatus(loan.id, 'disbursed')}
                      style={{ marginRight: '5px', backgroundColor: '#4CAF50', color: 'white' }}
                    >
                      Approve
                    </button>
                    <button
                      onClick={() => updateLoanStatus(loan.id, 'rejected')}
                      style={{ backgroundColor: '#f44336', color: 'white' }}
                    >
                      Reject
                    </button>
                  </>
                )}
                {loan.status !== 'pending' && <span>No actions available</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Loans;
